/* Full one-time import of the JSON generated by export-sqlite-to-json.js.
 * Legacy bcrypt password hashes cannot be transferred to Supabase Auth: users receive MIGRATION_PASSWORD
 * and must reset it. Run against an empty/staging project first. */
require(require('path').join(__dirname,'../backend/node_modules/dotenv')).config({path:require('path').join(__dirname,'../backend/.env')});
const fs=require('fs'),path=require('path'),{createClient}=require(path.join(__dirname,'../backend/node_modules/@supabase/supabase-js'));
const input=process.argv[2],password=process.env.MIGRATION_PASSWORD;if(!input||!password)throw new Error('Usage: MIGRATION_PASSWORD=<temporary-password> node scripts/migrate-json-to-supabase.js migration-data.json');
const db=createClient(process.env.SUPABASE_URL,process.env.SUPABASE_SERVICE_ROLE_KEY,{auth:{persistSession:false}}),dump=JSON.parse(fs.readFileSync(input));const userMap={},bullMap={},vetMap={},supplierMap={},orderMap={};
const insert=async(table,row)=>{const {data,error}=await db.from(table).insert(row).select('id').single();if(error)throw new Error(`${table}: ${error.message}`);return data.id};
(async()=>{
 for(const u of dump.users||[]){const email=`${u.username.toLowerCase()}@users.primegenetics.local`;const {data,error}=await db.auth.admin.createUser({email,password,email_confirm:true,user_metadata:{username:u.username,role:u.role}});if(error)throw new Error(`auth ${u.username}: ${error.message}`);userMap[u.id]=data.user.id;if(u.role==='admin'){const {error:e}=await db.from('users').update({role:'admin'}).eq('id',data.user.id);if(e)throw e}}
 for(const b of dump.bulls||[]){const {id,...row}=b;bullMap[id]=await insert('bulls',row)}
 for(const f of dump.farmers||[]){const {id,user_id,created_at,...row}=f;await db.from('farmers').insert({...row,user_id:userMap[user_id]})}
 for(const v of dump.vets||[]){const {id,user_id,created_at,...row}=v;vetMap[id]=await insert('vets',{...row,user_id:userMap[user_id]})}
 for(const s of dump.agri_suppliers||[]){const {id,user_id,created_at,...row}=s;supplierMap[id]=await insert('agri_suppliers',{...row,user_id:userMap[user_id]})}
 for(const c of dump.carts||[]){const {id,farmer_id,bull_id,...row}=c;await db.from('carts').insert({...row,farmer_id:userMap[farmer_id],bull_id:bullMap[bull_id]})}
 for(const i of dump.agri_supplier_inventory||[]){const {id,agri_supplier_id,bull_id,...row}=i;await db.from('agri_supplier_inventory').insert({...row,agri_supplier_id:supplierMap[agri_supplier_id],bull_id:bullMap[bull_id]})}
 for(const o of dump.orders||[]){const {id,farmer_id,vet_id,agri_supplier_id,...row}=o;orderMap[id]=await insert('orders',{...row,farmer_id:userMap[farmer_id],vet_id:vetMap[vet_id]||null,agri_supplier_id:supplierMap[agri_supplier_id]||null})}
 for(const i of dump.order_items||[]){const {id,order_id,bull_id,...row}=i;await db.from('order_items').insert({...row,order_id:orderMap[order_id],bull_id:bullMap[bull_id]})}
 console.log('Migration complete. Force a password reset for every migrated account.');
})().catch(e=>{console.error(e);process.exitCode=1});
